'use client';

import React, { useEffect, useState } from 'react';
import { useRouter, usePathname } from 'next/navigation';
import Link from 'next/link';
import { 
  Users, 
  MessageSquare, 
  History, 
  Wrench, 
  LogOut,
  ChevronDown,
  Loader2,
  Home,
  ShieldCheck
} from 'lucide-react';
import { cn } from '@/lib/utils';
import {
  DropdownMenu,
  DropdownMenuContent,
  DropdownMenuItem,
  DropdownMenuTrigger,
} from '@/components/ui/dropdown-menu';
import { useUser, useAuth } from '@/firebase';
import { signOut } from 'firebase/auth';
import { Icons } from '@/components/icons';

/**
 * @fileOverview Admin layout providing a global navbar with the traditional blue-green gradient.
 */
export default function AdminLayout({ children }: { children: React.ReactNode }) {
  const router = useRouter();
  const pathname = usePathname();
  const auth = useAuth();
  const { user, isUserLoading } = useUser();
  const [isAuthorized, setIsAuthorized] = useState(false);

  useEffect(() => {
    if (isUserLoading) return;

    const isAdmin = localStorage.getItem('isAdmin');
    if (isAdmin !== 'true') {
      router.push('/login');
    } else if (!user) {
      router.push('/login');
    } else {
      setIsAuthorized(true);
    }
  }, [user, isUserLoading, router]);

  const handleLogout = async () => {
    localStorage.removeItem('isAdmin');
    await signOut(auth);
    router.push('/login');
  };

  if (isUserLoading || !isAuthorized) {
    return (
      <div className="flex h-screen items-center justify-center bg-[#f1f5f9]">
        <Loader2 className="h-8 w-8 animate-spin text-primary" />
      </div>
    );
  }

  const navLinks = [
    { href: '/admin/dashboard', label: 'Dashboard', icon: Home },
    { href: '/admin/users', label: 'Users', icon: Users },
    { href: '/admin/feedback', label: 'Feedback', icon: MessageSquare },
    { href: '/admin/email-history', label: 'Email History', icon: History },
    { href: '/admin/tools', label: 'Tools', icon: Wrench, hasSub: true },
  ];

  return (
    <div className="min-h-screen bg-[#f1f5f9] flex flex-col font-body">
      {/* Global Navbar with traditional blue-green gradient spanning full width */}
      <header className="w-full bg-gradient-to-r from-[#1e3a8a] to-[#064e3b] text-white shadow-xl h-16 flex items-center justify-between px-6 z-50">
        <div className="flex items-center gap-10">
          <Link href="/admin/dashboard" className="flex items-center gap-2 group">
            <div className="w-8 h-8 bg-white rounded flex items-center justify-center shadow-sm">
              <Icons.Logo className="w-6 h-6" />
            </div>
            <span className="font-bold text-xl tracking-tight whitespace-nowrap">Wallet Tally Admin</span>
          </Link>

          <nav className="hidden lg:flex items-center gap-1">
            {navLinks.map((link) => (
              <Link
                key={link.href}
                href={link.href}
                className={cn(
                  "flex items-center gap-2 px-4 py-2 transition-all text-sm font-bold rounded-lg",
                  pathname === link.href
                    ? "bg-white/20 text-white shadow-inner" 
                    : "text-white/80 hover:text-white hover:bg-white/10"
                )}
              >
                <link.icon className="w-4.5 h-4.5" />
                {link.label}
                {link.hasSub && <ChevronDown className="w-4 h-4 ml-0.5 opacity-50" />}
              </Link>
            ))}
          </nav>
        </div>

        <div className="flex items-center gap-4">
          <DropdownMenu>
            <DropdownMenuTrigger asChild>
              <button className="flex items-center gap-2 px-4 py-2 rounded-xl hover:bg-white/10 transition-colors focus:outline-none">
                <div className="flex items-center gap-2">
                  <ShieldCheck className="w-5 h-5 text-white" />
                  <span className="text-sm font-bold text-white whitespace-nowrap">WalletTallyAdmin</span>
                </div>
                <ChevronDown className="w-4 h-4 opacity-60" />
              </button>
            </DropdownMenuTrigger>
            <DropdownMenuContent align="end" className="w-56 rounded-2xl p-2 shadow-2xl border-0 mt-2 bg-white">
              <div className="px-4 py-3 border-b border-slate-50 mb-1">
                 <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Admin Control</p>
                 <p className="text-xs font-bold text-slate-700 mt-1 truncate">Admin Session</p>
              </div>
              <DropdownMenuItem onClick={handleLogout} className="text-red-500 font-bold focus:text-red-500 focus:bg-red-50 cursor-pointer rounded-xl h-11 px-4">
                <LogOut className="w-4 h-4 mr-2" /> End Session
              </DropdownMenuItem>
            </DropdownMenuContent>
          </DropdownMenu>
        </div>
      </header>

      {/* Main Content Area */}
      <main className="flex-1 container mx-auto p-4 md:p-10 space-y-6">
        <div className="pb-12">
          {children}
        </div>
      </main>
    </div>
  );
}
